    close: "Zavřít",
    install_safari_title: "Přidat na domovskou obrazovku",
    install_safari_subtitle: "Instalace na iPhone/iPad:",
    install_step1: "Klikněte na tlačítko „Sdílet“ (ikona šipky)",
    install_step2: "Vyberte „Přidat na domovskou obrazovku“",
